import math

THRESHOLD = 1 # The threshold for switching to standard matrix multiplication.
              # If set to 1, recursion continues until 1x1 matrices are multiplied
              # using standard multiplication. A higher threshold (e.g., 16 or 32)
              # is often used for performance in practice.


def _standard_matrix_multiply(A, B):
    n = len(A)
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                C[i][j] += A[i][k] * B[k][j]
    return C


def _matrix_add(A, B):
    n = len(A)
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            C[i][j] = A[i][j] + B[i][j]
    return C


def _matrix_sub(A, B):
    n = len(A)
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            C[i][j] = A[i][j] - B[i][j]
    return C


def _split_matrix(matrix):
    n = len(matrix)
    half = n // 2
    A11 = [[matrix[i][j] for j in range(half)] for i in range(half)]
    A12 = [[matrix[i][j] for j in range(half, n)] for i in range(half)]
    A21 = [[matrix[i][j] for j in range(half)] for i in range(half, n)]
    A22 = [[matrix[i][j] for j in range(half, n)] for i in range(half, n)]
    return A11, A12, A21, A22


def _join_matrices(C11, C12, C21, C22):
    half = len(C11)
    n = half * 2
    C = [[0 for _ in range(n)] for _ in range(n)]
    for i in range(half):
        for j in range(half):
            C[i][j] = C11[i][j]
            C[i][j + half] = C12[i][j]
            C[i + half][j] = C21[i][j]
            C[i + half][j + half] = C22[i][j]
    return C


def _pad_matrices(A, B, target_dim):
    original_n = len(A)
    A_padded = [[0 for _ in range(target_dim)] for _ in range(target_dim)]
    B_padded = [[0 for _ in range(target_dim)] for _ in range(target_dim)]

    for r in range(original_n):
        for c in range(original_n):
            A_padded[r][c] = A[r][c]
            B_padded[r][c] = B[r][c]
    return A_padded, B_padded


def _unpad_matrix(padded_matrix, original_n_rows, original_n_cols):
    result = [[0 for _ in range(original_n_cols)] for _ in range(original_n_rows)]
    for r in range(original_n_rows):
        for c in range(original_n_cols):
            result[r][c] = padded_matrix[r][c]
    return result


def strassen_multiply(A, B):
    n = len(A)

    if n <= THRESHOLD:
        return _standard_matrix_multiply(A, B)

    original_n = n
    if not (n and (n & (n - 1)) == 0):
        next_power_of_2 = 1
        while next_power_of_2 < n:
            next_power_of_2 <<= 1
        A_padded, B_padded = _pad_matrices(A, B, next_power_of_2)
        n = next_power_of_2
    else:
        A_padded, B_padded = A, B

    A11, A12, A21, A22 = _split_matrix(A_padded)
    B11, B12, B21, B22 = _split_matrix(B_padded)

    P1 = strassen_multiply(_matrix_add(A11, A22), _matrix_add(B11, B22))
    P2 = strassen_multiply(_matrix_add(A21, A22), B11)
    P3 = strassen_multiply(A11, _matrix_sub(B12, B22))
    P4 = strassen_multiply(A22, _matrix_sub(B21, B11))
    P5 = strassen_multiply(_matrix_add(A11, A12), B22)
    P6 = strassen_multiply(_matrix_sub(A21, A11), _matrix_add(B11, B12))
    P7 = strassen_multiply(_matrix_sub(A12, A22), _matrix_add(B21, B22))

    C11 = _matrix_add(_matrix_sub(_matrix_add(P1, P4), P5), P7)
    C12 = _matrix_add(P3, P5)
    C21 = _matrix_add(P2, P4)
    C22 = _matrix_add(_matrix_sub(_matrix_add(P1, P3), P2), P6)

    C_padded = _join_matrices(C11, C12, C21, C22)

    return _unpad_matrix(C_padded, original_n, original_n)
